k=A.O(A.a([a.Ly("Families who want ongoing guidance","Book Full Support","Hello MiniGuru! I want to book the Full Virtual Support plan.",A.a([a1,a2,a3,"Monthly 30-min video calls for 6 months","WhatsApp support as questions arise","MiniGuru community access \u2014 6 months","Project review and suggestions after each sharing"],k),!0,"\ud83d\udcbb","Full Virtual Support","\u20b93,999","Most Popular",B.b3),B.S,a.Ly("Families anywhere in India","Book Virtual Setup","Hello MiniGuru! I want to book the Virtual Setup plan.",A.a([a1,a2,a3,"One follow-up call after setup (30 min)","MiniGuru community access \u2014 3 months"],k),!1,"\ud83d\udcf1","Virtual Setup","\u20b91,499","Starter",B.hU),B.S,a.Ly("Families in Bhopal, Ujjain, Pune and nearby areas","Enquire for In-Person","Hello MiniGuru! I am interested in the In-Person Setup. Please let me know if it is available in my city.",A.a(["Everything in Full Virtual Support","2-hour in-person setup session at your home","First making session with your child on the day","3 in-person follow-up visits (monthly)"],k),!1,"\ud83e\udd1d","In-Person Setup","\u20b96,999 + travel","Select Cities",B.Mn)],a5),B.k,B.h,B.f)
